import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"カード強化","description":"","frontmatter":{},"headers":[],"relativePath":"ja/cards/upgrade.md","filePath":"ja/cards/upgrade.md","lastUpdated":1775394001000}'),r={name:"ja/cards/upgrade.md"};function i(s,t,n,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="カード強化" tabindex="-1">カード強化 <a class="header-anchor" href="#カード強化" aria-label="Permalink to &quot;カード強化&quot;">​</a></h1><p>指令カードおよび魂覚醒カードは<strong>最大Lv.6</strong>まで強化可能です。強化により効果値が向上し、一部カードは追加効果が解放されます。</p><h2 id="強化レベル" tabindex="-1">強化レベル <a class="header-anchor" href="#強化レベル" aria-label="Permalink to &quot;強化レベル&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">レベル</th><th style="text-align:left;">効果</th><th style="text-align:left;">必要素材</th></tr></thead><tbody><tr><td style="text-align:center;">Lv.1</td><td style="text-align:left;">基本性能</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:center;">Lv.2</td><td style="text-align:left;">効果値+10%</td><td style="text-align:left;">カード素材（低）</td></tr><tr><td style="text-align:center;">Lv.3</td><td style="text-align:left;">効果値+20%</td><td style="text-align:left;">カード素材（中）</td></tr><tr><td style="text-align:center;">Lv.4</td><td style="text-align:left;">効果値+35%、追加効果解放の場合あり</td><td style="text-align:left;">カード素材（高）</td></tr><tr><td style="text-align:center;">Lv.5</td><td style="text-align:left;">効果値+50%</td><td style="text-align:left;">カード素材（極）</td></tr><tr><td style="text-align:center;">Lv.6</td><td style="text-align:left;">効果値+70%、最終追加効果解放</td><td style="text-align:left;">カード素材（極）＋特殊素材</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Lv.6への強化には通常のカード素材に加えて特殊素材が必要です。特殊素材は<a href="./../stages/challenge.html">チャレンジステージ</a>や<a href="./../modes/smelting.html">冶錬室</a>で入手可能です。</p></div><h2 id="強化素材の入手方法" tabindex="-1">強化素材の入手方法 <a class="header-anchor" href="#強化素材の入手方法" aria-label="Permalink to &quot;強化素材の入手方法&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">素材</th><th style="text-align:left;">主な入手先</th></tr></thead><tbody><tr><td style="text-align:left;">カード素材（低）</td><td style="text-align:left;">メインステージ、資源ステージ</td></tr><tr><td style="text-align:left;">カード素材（中）</td><td style="text-align:left;">資源ステージ、派遣</td></tr><tr><td style="text-align:left;">カード素材（高）</td><td style="text-align:left;">チャレンジステージ、イベント</td></tr><tr><td style="text-align:left;">カード素材（極）</td><td style="text-align:left;">チャレンジステージ（高難度）、ショップ</td></tr><tr><td style="text-align:left;">特殊素材</td><td style="text-align:left;">チャレンジステージ、冶錬室</td></tr></tbody></table><h2 id="強化の優先度" tabindex="-1">強化の優先度 <a class="header-anchor" href="#強化の優先度" aria-label="Permalink to &quot;強化の優先度&quot;">​</a></h2><ol><li><strong>メインアタッカーの主力指令カードをLv.3に</strong> — コスパが最も良い</li><li><strong>支援型のバフカードをLv.3に</strong> — 編成全体の火力が向上</li><li><strong>メインアタッカーの魂覚醒カードをLv.4に</strong> — バースト威力が大幅向上</li><li><strong>主力カードをLv.6に</strong> — 終盤コンテンツの攻略に必要</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Lv.4以降は素材消費が急増します。複数キャラを均等に強化するより、主力1体を集中強化する方が効率的です。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">カードシステム概要</a></li><li><a href="./list.html">カード一覧</a></li><li><a href="./../awakeners/leveling.html">育成ガイド</a></li><li><a href="./../items/materials.html">素材一覧</a></li></ul>',12)])])}const x=e(r,[["render",i]]);export{f as __pageData,x as default};
